module top_module(
  input clk,
  input reset,
  input enable,
  input d,
  output reg q
);reg unused_q_next;

  always @(posedge clk) begin
    if (reset) begin
      unused_q_next <= 1'b0;
    end else if (enable) begin
      unused_q_next <= d;
    end else begin
      unused_q_next <= q;
    end
  end

  assign q = unused_q_next;

endmodule
